var slides = document.querySelectorAll(".slide");
var N = slides.length;
var track = document.querySelector(".track");
window.addEventListener("scroll", function(){
  var rect = track.getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  var idx = Math.min(Math.floor(p * N), N - 1);
  slides.forEach(function(s, i){ s.classList.toggle("is-on", i === idx); });
}, { passive: true });

.stage { overflow: hidden; }
.rail { display: flex; width: 400vw; height: 100vh; }
.slide { width: 100vw; height: 100vh; flex-shrink: 0; }

var rail = document.querySelector(".rail");
var N = 4;
window.addEventListener("scroll", function(){
  var rect = document.querySelector(".track").getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  rail.style.transform = "translateX(" + (-p * (N - 1) * 100) + "vw)";
}, { passive: true });

var slides = document.querySelectorAll(".slide");
var N = slides.length;
window.addEventListener("scroll", function(){
  var rect = document.querySelector(".track").getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  slides.forEach(function(s, i){
    var pos = p * N - i;
    var scale = pos < 0 ? 0.8 + 0.2 * (1 + pos) : pos > 1 ? 1 + 0.4 * (pos - 1) : 0.8 + 0.6 * pos;
    var op = pos < 0 || pos > 1 ? 0 : Math.min(1, pos * 2) * (1 - Math.max(0, pos - 0.5) * 2);
    s.style.opacity = op; s.style.transform = "scale(" + scale + ")";
  });
}, { passive: true });

var slides = document.querySelectorAll(".slide");
var N = slides.length;
window.addEventListener("scroll", function(){
  var rect = document.querySelector(".track").getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  slides.forEach(function(s, i){
    var pos = p * N - i;
    var local = Math.max(0, Math.min(1, pos + 1));
    s.style.transform = "translateY(" + (100 * (1 - local)) + "%)";
    s.style.zIndex = i;
  });
}, { passive: true });

