var slides = document.querySelectorAll(".slide");
var N = slides.length;
window.addEventListener("scroll", function(){
  var rect = document.querySelector(".track").getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  slides.forEach(function(s, i){
    var pos = p * N - i;
    s.style.opacity = 1 - Math.min(1, Math.abs(pos));
    s.style.transform = "rotateY(" + (pos * 90) + "deg) translateZ(" + (-Math.abs(pos) * 200) + "px)";
  });
}, { passive: true });

var slides = document.querySelectorAll(".slide");
window.addEventListener("scroll", function(){
  var rect = document.querySelector(".track").getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  slides.forEach(function(s, i){
    if (i === 0) return;
    var pos = p * slides.length - i + 1;
    var inset = pos <= 0 ? 100 : pos >= 1 ? 0 : (1 - pos) * 100;
    s.style.clipPath = "inset(" + inset + "% 0 0 0)";
    s.style.zIndex = i;
  });
}, { passive: true });

var slides = document.querySelectorAll(".slide");
var N = slides.length;
window.addEventListener("scroll", function(){
  var rect = document.querySelector(".track").getBoundingClientRect();
  var p = Math.max(0, Math.min(1, -rect.top / (rect.height - window.innerHeight)));
  slides.forEach(function(s, i){
    var pos = p * N - i;
    s.style.opacity = 1 - Math.abs(pos);
    s.style.transform = "scale(" + (0.9 + (1 - Math.abs(pos)) * 0.1 + Math.max(0, pos) * 0.1) + ")";
  });
}, { passive: true });

var caps = document.querySelectorAll(".cap");
var N = caps.length;
